var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여긴 어디지......?","JPN":"ここはどこ……？","ENG":"Where... am I?","TWN":"這裡是哪……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭔가 머리 아픈 대화를 한참 한 것 같은데......","JPN":"なんだか頭が痛くなる会話をしたような……","ENG":"I feel like I had a long, boring talk about something complicated...","TWN":"我好像進行了很頭疼的對話……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"어지간하면 참아 보려 했는데, 한심해서 안 되겠군.","JPN":"できるだけ我慢しようと思ったけど、情けなさすぎてダメだ。","ENG":"I was going to let you off the hook, but you're just so pathetic.","TWN":"本來我想忍住，但實在是看不下去了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L6_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"저런 재활용품 상대로 고전하는 것도 모자라 코앞에서 하는 정신간섭에 당하다니, 생각은 하면서 사는 거냐?","JPN":"あんなリサイクル品のゴミを相手に苦戦するだけではなく、精神干渉にもやられるなんてどういうこと？","ENG":"As if it wasn't enough you let some recycled junk wear you down, now you let them control your mind?","TWN":"與那種被再利用的敵人進行苦戰不說，還受到精神干擾的影響。你難道沒有腦子嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"넌......! 그 때 심상세계에서 시비를 걸었던 녀석이잖아?!","JPN":"あんたは……！　あの時心の世界で私にケンカを売ってきた奴！？","ENG":"You! You're that one that picked a fight with me in the mental world!","TWN":"你是……！之前在內心世界找我麻煩的傢伙？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직 살아 있었어?","JPN":"まだ生きてたの？","ENG":"You're still alive?","TWN":"你居然還活著？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"말하는 투를 봐선 내가 누구인지 아직도 못 알아차렸나 보군.","JPN":"その態度じゃ、私が誰なのかまだ気付いていないようだね。","ENG":"It sounds like you don't fully realize who I am yet.","TWN":"聽你的語氣，應該是還沒意識到我是誰。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"머리가 나쁜 건지, 눈치가 없는 건지 원......","JPN":"頭が悪いのか、勘が鈍いのか……ったく。","ENG":"I can't tell if you're stupid or clueless...","TWN":"也不知道是腦子不好，還是眼光不好……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"하긴 둘 다 집안 내력이긴 하지.","JPN":"まあ、どっちも家柄のせいなんだけど。","ENG":"Oh well, I suppose those run in the family.","TWN":"也對，這兩個也都是家族遺傳的吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐야? 갑자기 나타나선 남의 집안 험담을 하고 그래?","JPN":"なっ？　いきなり現れて人の家柄をバカにして！","ENG":"H-huh? Why do you have to drag my family into this?","TWN":"什麼？你突然出現還對別人的家庭說三道四？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"남의 집안이라...... 뭐, 됐다.","JPN":"人の家柄か……まあ、いいや。","ENG":"Your family, huh? Oh, whatever.","TWN":"別人的家庭……算了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"이미 숙명 구속구가 파괴된 이상 조금은 싸우는 법을 가르쳐 줘야겠지.","JPN":"すでに宿命拘束具が破壊された以上、戦い方について少し教えてやらないと。","ENG":"Since your Destiny Fetter is already destroyed, I might as well teach you a bit about how to fight.","TWN":"現在宿命拘束器已經受到破壞，該教你一些戰鬥的方法了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"지금 같은 한심한 실력으로는 변화고 뭐고 당장 내일모레 객사나 안 하면 다행이니까.","JPN":"今みたいな情けない実力じゃ変化するどころか、すぐにでも死んじゃいそうだし。","ENG":"With your pathetic skills, you'll be lucky if you live to see another day, let alone undergo any change.","TWN":"單憑現在這樣的實力，別說變化，明天沒直接客死他鄉就已經算是幸運了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"설마 또 내 몸을 빼앗으려는 거야?","JPN":"もしかして、また私の体を乗っ取る気？","ENG":"Are you trying to steal my body again?","TWN":"不會是又要霸佔我的身體吧？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그 싸움은 이미 끝났어.","JPN":"その戦いはもう終わったよ。","ENG":"That fight is already over.","TWN":"那個戰鬥已經結束了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"이제 난 그저 네 무의식 속을 떠도는 낡은 기억 덩어리일 뿐이야.","JPN":"私はもう君の無意識の中を彷徨う、ただの古い記憶の塊にすぎない。","ENG":"I'm just a fragment of your old memory, floating around your subconscious.","TWN":"現在我只是在你的潛意識中遊蕩的陳舊記憶而已。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그러니...... 내 기억을 받아가라.","JPN":"だから……私の記憶を受け取って。","ENG":"So... Take my memories.","TWN":"所以……接受我的記憶吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"기억이라니, 무슨 소릴...... 어라?","JPN":"記憶って、なにを……あれ？","ENG":"Memories? What are you talking about— huh?","TWN":"記憶？你在說什麼……咦？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"검술, 전투이론? 이게 다 내 기억이라고......?","JPN":"剣術、戦闘理論？　これが全部私の記憶……？","ENG":"Swordcraft? Combat theories? All these are my memories?","TWN":"劍術，戰鬥理論？這些都是我的記憶……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"넌 누구보다 강한 잠재력을 가지고 있어.","JPN":"君には誰よりも強い潜在能力がある。","ENG":"You have far greater potential than anyone else.","TWN":"你擁有比任何人都強大的潛力。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그리고 제대로만 쓴다면 네 검, 울브즈베인은 신도 베어 죽일 수 있다.","JPN":"そしてちゃんと使いこなせるなら君の剣、ウルブズベインは神すらも斬り殺せる。","ENG":"You could even slay a god with your sword Wolvesbane, if you use it properly.","TWN":"如果能正確使用的話，你的劍，狼之災禍甚至連神都能斬殺。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"지금부터 그걸 어떻게 써야 하는지 알려 주지.","JPN":"それをどうやって使うか教えてあげる。","ENG":"Now, I'll teach you how to do that.","TWN":"那麼現在開始告訴你如何使用。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>울브즈베인 – 레거시 모드 기동</color>","JPN":"<color=#ffd34c>ウルブズベイン – レガシーモード起動</color>","ENG":"<color=#ffd34c>Wolvesbane - Legacy Mode activated.</color>","TWN":"<color=#ffd34c>狼之災禍 -  遺留模式啟動</color>"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_08"},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 - 발퀴레 근접 반응형 집속검</color>","JPN":"<color=#ffd34c>戦術アップデート – ワルキューレ近接反応型集束剣</color>","ENG":"<color=#ffd34c>Tactical update - Valkyrie melee response focus blade.</color>","TWN":"<color=#ffd34c>戰術升級——女武神近戰反應型聚能劍</color>"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_06"},{"id":"L34_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"아......?","JPN":"え……？","ENG":"Huh?","TWN":"啊……？"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"캬아██아아███아아......!!","JPN":"グア██アア███アッ！！","ENG":"Ky██aa███ah!","TWN":"咳啊██啊啊███啊啊……！！"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>적성 개체. 섬멸 개시.</color>","JPN":"<color=#ffd34c>敵性個体。殲滅開始。</color>","ENG":"<color=#ffd34c>Hostile detected. Commencing annihilation.</color>","TWN":"<color=#ffd34c>適能個體，殲滅開始。</color>"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"}]`);export{e as default};